#include <bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=2005;
int n,c,x[N],y[N],f[N];
struct node
{
	int u,v,w;
	bool operator<(const node other) const
	{
		return w<other.w;
	}
};
vector<node> v;
int find(int x)
{
	if(f[x]==x)
	{
		return x;
	}
	return f[x]=find(f[x]);
}
int main()
{
	cin>>n>>c;
	for(int i=1;i<=n;i++) cin>>x[i]>>y[i];
	for(int i=1;i<=n;i++)
	{
		f[i]=i;
		for(int j=1;j<=n;j++)
		{
			if(j==i) continue;
			int t=abs(x[i]-x[j])*abs(x[i]-x[j])+abs(y[i]-y[j])*abs(y[i]-y[j]);
			if(t>=c) v.push_back(node{i,j,t});
		}
	}
	sort(v.begin(),v.end());
	ll sum=0,cnt=0;
	for(int i=0;i<v.size();i++)
	{
		node t=v[i];
		int fu=find(t.u),fv=find(t.v);
		if(fu==fv) continue;
		cnt++;
		sum+=t.w;
		f[fu]=fv;
	}
	if(cnt<n-1) cout<<-1;
	else cout<<sum;
	return 0;
}
